1	import {
2	  Experimental_VideoModelV3,
3	  ImageModelV3,
4	  NoSuchModelError,
5	  ProviderV3,
6	  SpeechModelV3,
7	  TranscriptionModelV3,
8	} from '@ai-sdk/provider';
9	import type { FetchFunction } from '@ai-sdk/provider-utils';
10	import {
11	  withoutTrailingSlash,
12	  withUserAgentSuffix,
13	} from '@ai-sdk/provider-utils';
14	import { FalImageModel } from './fal-image-model';
15	import { FalImageModelId } from './fal-image-settings';
16	import { FalTranscriptionModelId } from './fal-transcription-options';
17	import { FalTranscriptionModel } from './fal-transcription-model';
18	import { FalSpeechModelId } from './fal-speech-settings';
19	import { FalSpeechModel } from './fal-speech-model';
20	import { FalVideoModel } from './fal-video-model';
21	import { FalVideoModelId } from './fal-video-settings';
22	import { VERSION } from './version';
23	
24	export interface FalProviderSettings {
25	  /**
26	   * fal.ai API key. Default value is taken from the `FAL_API_KEY` environment
27	   * variable, falling back to `FAL_KEY`.
28	   */
29	  apiKey?: string;
30	
31	  /**
32	   * Base URL for the API calls.
33	   * The default prefix is `https://fal.run`.
34	   */
35	  baseURL?: string;
36	
37	  /**
38	   * Custom headers to include in the requests.
39	   */
40	  headers?: Record<string, string>;
41	
42	  /**
43	   * Custom fetch implementation. You can use it as a middleware to intercept
44	   * requests, or to provide a custom fetch implementation for e.g. testing.
45	   */
46	  fetch?: FetchFunction;
47	}
48	
49	export interface FalProvider extends ProviderV3 {
50	  /**
51	   * Creates a model for image generation.
52	   */
53	  image(modelId: FalImageModelId): ImageModelV3;
54	
55	  /**
56	   * Creates a model for image generation.
57	   */
58	  imageModel(modelId: FalImageModelId): ImageModelV3;
59	
60	  /**
61	   * Creates a model for transcription.
62	   */
63	  transcription(modelId: FalTranscriptionModelId): TranscriptionModelV3;
64	
65	  /**
66	   * Creates a model for video generation.
67	   */
68	  video(modelId: FalVideoModelId): Experimental_VideoModelV3;
69	
70	  /**
71	   * Creates a model for video generation.
72	   */
73	  videoModel(modelId: FalVideoModelId): Experimental_VideoModelV3;
74	
75	  /**
76	   * Creates a model for speech generation.
77	   */
78	  speech(modelId: FalSpeechModelId): SpeechModelV3;
79	
80	  /**
81	   * @deprecated Use `embeddingModel` instead.
82	   */
83	  textEmbeddingModel(modelId: string): never;
84	}
85	
86	const defaultBaseURL = 'https://fal.run';
87	
88	function loadFalApiKey({
89	  apiKey,
90	  description = 'fal.ai',
91	}: {
92	  apiKey: string | undefined;
93	  description?: string;
94	}): string {
95	  if (typeof apiKey === 'string') {
96	    return apiKey;
97	  }
98	
99	  if (apiKey != null) {
100	    throw new Error(`${description} API key must be a string.`);
101	  }
102	
103	  if (typeof process === 'undefined') {
104	    throw new Error(
105	      `${description} API key is missing. Pass it using the 'apiKey' parameter. Environment variables are not supported in this environment.`,
106	    );
107	  }
108	
109	  let envApiKey = process.env.FAL_API_KEY;
110	  if (envApiKey == null) {
111	    envApiKey = process.env.FAL_KEY;
112	  }
113	
114	  if (envApiKey == null) {
115	    throw new Error(
116	      `${description} API key is missing. Pass it using the 'apiKey' parameter or set either the FAL_API_KEY or FAL_KEY environment variable.`,
117	    );
118	  }
119	
120	  if (typeof envApiKey !== 'string') {
121	    throw new Error(
122	      `${description} API key must be a string. The value of the environment variable is not a string.`,
123	    );
124	  }
125	
126	  return envApiKey;
127	}
128	
129	/**
130	 * Create a fal.ai provider instance.
131	 */
132	export function createFal(options: FalProviderSettings = {}): FalProvider {
133	  const baseURL = withoutTrailingSlash(options.baseURL ?? defaultBaseURL);
134	  const getHeaders = () =>
135	    withUserAgentSuffix(
136	      {
137	        Authorization: `Key ${loadFalApiKey({
138	          apiKey: options.apiKey,
139	        })}`,
140	        ...options.headers,
141	      },
142	      `ai-sdk/fal/${VERSION}`,
143	    );
144	
145	  const createImageModel = (modelId: FalImageModelId) =>
146	    new FalImageModel(modelId, {
147	      provider: 'fal.image',
148	      baseURL: baseURL ?? defaultBaseURL,
149	      headers: getHeaders,
150	      fetch: options.fetch,
151	    });
152	
153	  const createSpeechModel = (modelId: FalSpeechModelId) =>
154	    new FalSpeechModel(modelId, {
155	      provider: `fal.speech`,
156	      url: ({ path }) => path,
157	      headers: getHeaders,
158	      fetch: options.fetch,
159	    });
160	
161	  const createTranscriptionModel = (modelId: FalTranscriptionModelId) =>
162	    new FalTranscriptionModel(modelId, {
163	      provider: `fal.transcription`,
164	      url: ({ path }) => path,
165	      headers: getHeaders,
166	      fetch: options.fetch,
167	    });
168	
169	  const createVideoModel = (modelId: FalVideoModelId) =>
170	    new FalVideoModel(modelId, {
171	      provider: 'fal.video',
172	      url: ({ path }) => path,
173	      headers: getHeaders,
174	      fetch: options.fetch,
175	    });
176	
177	  const embeddingModel = (modelId: string) => {
178	    throw new NoSuchModelError({
179	      modelId,
180	      modelType: 'embeddingModel',
181	    });
182	  };
183	
184	  return {
185	    specificationVersion: 'v3' as const,
186	    imageModel: createImageModel,
187	    image: createImageModel,
188	    languageModel: (modelId: string) => {
189	      throw new NoSuchModelError({
190	        modelId,
191	        modelType: 'languageModel',
192	      });
193	    },
194	    speech: createSpeechModel,
195	    embeddingModel,
196	    textEmbeddingModel: embeddingModel,
197	    transcription: createTranscriptionModel,
198	    video: createVideoModel,
199	    videoModel: createVideoModel,
200	  };
201	}
202	
203	/**
204	 * Default fal.ai provider instance.
205	 */
206	export const fal = createFal();
