export const pixelArtImageModelOptionsSchema = lazySchema(() =>
  zodSchema(
    z
      .object({
        /**
         * The visual style to apply to the generated image.
         * - `'pixel'`: Classic pixel art look with blocky, discrete pixels.
         * - `'retro'`: Retro-inspired style reminiscent of early game consoles.
         * - `'8bit'`: 8-bit era color palette and rendering style.
         */
        style: z.enum(['pixel', 'retro', '8bit']).nullish(),

        /**
         * Controls the size of each pixel block in the output image.
         * Higher values produce larger, more visible pixels.
         * Must be between 1 and 64. Defaults to 8.
         */
        pixelDensity: z.number().min(1).max(64).nullish(),
      })
      .passthrough(),
  ),
);

export type PixelArtImageModelOptions = InferSchema<
  typeof pixelArtImageModelOptionsSchema
>;

