import type { FetchFunction } from '@ai-sdk/provider-utils';
import { createTestServer } from '@ai-sdk/test-server/with-vitest';
import { describe, expect, it } from 'vitest';
import { PixelArtImageModel } from './pixelart-image-model';

const TEST_PROMPT = 'A pixel art castle at sunset';

// Minimal 1x1 red PNG encoded as base64
const TEST_B64_IMAGE =
  'iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mP8z8BQDwADhQGAWjR9awAAAABJRU5ErkJggg==';

function createBasicModel({
  headers,
  fetch,
  currentDate,
}: {
  headers?: Record<string, string | undefined>;
  fetch?: FetchFunction;
  currentDate?: () => Date;
} = {}) {
  return new PixelArtImageModel('pixelart-standard', {
    provider: 'pixelart.image',
    baseURL: 'https://api.example.com/v1',
    headers: headers ?? { Authorization: 'Bearer test-key' },
    fetch,
    _internal: {
      currentDate,
    },
  });
}

describe('PixelArtImageModel', () => {
  const server = createTestServer({
    'https://api.example.com/v1/images/generate': {
      response: {
        type: 'json-value',
        body: {
          images: [{ b64_json: TEST_B64_IMAGE, seed: 42 }],
          model: 'pixelart-standard',
          created: 1700000000,
        },
      },
    },
  });

  describe('constructor', () => {
    it('should expose correct provider and model information', () => {
      const model = createBasicModel();

      expect(model.provider).toBe('pixelart.image');
      expect(model.modelId).toBe('pixelart-standard');
      expect(model.specificationVersion).toBe('v3');
      expect(model.maxImagesPerCall).toBe(4);
    });
  });

  describe('doGenerate', () => {
    it('should send the correct request body with prompt and model', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt: TEST_PROMPT,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        model: 'pixelart-standard',
        prompt: TEST_PROMPT,
        n: 1,
      });
    });

    it('should include size when provided', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt: TEST_PROMPT,
        n: 1,
        size: '512x512',
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        model: 'pixelart-standard',
        prompt: TEST_PROMPT,
        n: 1,
        size: '512x512',
      });
    });

    it('should include seed when provided', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt: TEST_PROMPT,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: 99,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        model: 'pixelart-standard',
        prompt: TEST_PROMPT,
        n: 1,
        seed: 99,
      });
    });

    it('should send style provider option as `style` in request body', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt: TEST_PROMPT,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {
          pixelart: { style: '8bit' },
        },
        files: undefined,
        mask: undefined,
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        model: 'pixelart-standard',
        prompt: TEST_PROMPT,
        n: 1,
        style: '8bit',
      });
    });

    it('should send pixelDensity provider option as `pixel_density` in request body', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt: TEST_PROMPT,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {
          pixelart: { pixelDensity: 16 },
        },
        files: undefined,
        mask: undefined,
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        model: 'pixelart-standard',
        prompt: TEST_PROMPT,
        n: 1,
        pixel_density: 16,
      });
    });

    it('should send all provider options together', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt: TEST_PROMPT,
        n: 2,
        size: '256x256',
        aspectRatio: undefined,
        seed: 7,
        providerOptions: {
          pixelart: { style: 'retro', pixelDensity: 8 },
        },
        files: undefined,
        mask: undefined,
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        model: 'pixelart-standard',
        prompt: TEST_PROMPT,
        n: 2,
        size: '256x256',
        seed: 7,
        style: 'retro',
        pixel_density: 8,
      });
    });

    it('should pass custom headers', async () => {
      const modelWithHeaders = createBasicModel({
        headers: {
          Authorization: 'Bearer my-key',
          'X-Custom-Header': 'custom-value',
        },
      });

      await modelWithHeaders.doGenerate({
        prompt: TEST_PROMPT,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
        headers: { 'X-Request-Header': 'request-value' },
      });

      expect(server.calls[0].requestHeaders).toMatchObject({
        authorization: 'Bearer my-key',
        'x-custom-header': 'custom-value',
        'x-request-header': 'request-value',
      });
    });

    it('should decode base64 images to Uint8Array', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt: TEST_PROMPT,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(result.images).toHaveLength(1);
      expect(result.images[0]).toBeInstanceOf(Uint8Array);
      expect(result.images[0].length).toBeGreaterThan(0);
    });

    it('should return multiple images when n > 1', async () => {
      server.urls['https://api.example.com/v1/images/generate'].response = {
        type: 'json-value',
        body: {
          images: [
            { b64_json: TEST_B64_IMAGE, seed: 1 },
            { b64_json: TEST_B64_IMAGE, seed: 2 },
          ],
          model: 'pixelart-standard',
          created: 1700000000,
        },
      };

      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt: TEST_PROMPT,
        n: 2,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(result.images).toHaveLength(2);
      expect(result.images[0]).toBeInstanceOf(Uint8Array);
      expect(result.images[1]).toBeInstanceOf(Uint8Array);
    });

    it('should include timestamp, modelId, and headers in response metadata', async () => {
      const testDate = new Date('2024-06-01T12:00:00Z');
      const model = createBasicModel({ currentDate: () => testDate });

      const result = await model.doGenerate({
        prompt: TEST_PROMPT,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(result.response).toStrictEqual({
        timestamp: testDate,
        modelId: 'pixelart-standard',
        headers: expect.any(Object),
      });
    });

    it('should include provider metadata with created timestamp and image info', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt: TEST_PROMPT,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(result.providerMetadata).toStrictEqual({
        pixelart: {
          created: 1700000000,
          images: [{ seed: 42 }],
        },
      });
    });

    it('should return empty warnings array', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt: TEST_PROMPT,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(result.warnings).toStrictEqual([]);
    });

    it('should handle API errors', async () => {
      server.urls['https://api.example.com/v1/images/generate'].response = {
        type: 'error',
        status: 400,
        body: JSON.stringify({
          error: {
            message: 'Invalid size parameter',
            type: 'invalid_request_error',
            code: 'invalid_size',
          },
        }),
      };

      const model = createBasicModel();

      await expect(
        model.doGenerate({
          prompt: TEST_PROMPT,
          n: 1,
          size: '99x99',
          aspectRatio: undefined,
          seed: undefined,
          providerOptions: {},
          files: undefined,
          mask: undefined,
        }),
      ).rejects.toMatchObject({
        message: 'Invalid size parameter',
        statusCode: 400,
      });
    });

    it('should use model ID from API response when available', async () => {
      server.urls['https://api.example.com/v1/images/generate'].response = {
        type: 'json-value',
        body: {
          images: [{ b64_json: TEST_B64_IMAGE }],
          model: 'pixelart-standard-v2',
          created: 1700000000,
        },
      };

      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt: TEST_PROMPT,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(result.response.modelId).toBe('pixelart-standard-v2');
    });

    it('should fall back to constructor modelId when API response omits model', async () => {
      server.urls['https://api.example.com/v1/images/generate'].response = {
        type: 'json-value',
        body: {
          images: [{ b64_json: TEST_B64_IMAGE }],
          created: 1700000000,
        },
      };

      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt: TEST_PROMPT,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(result.response.modelId).toBe('pixelart-standard');
    });
  });
});

