        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {
          pixelart: { style: '8bit' },
        },
        files: undefined,
        mask: undefined,
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        model: 'pixelart-standard',
        prompt: TEST_PROMPT,
        n: 1,
        style: '8bit',
      });
    });

    it('should send pixelDensity provider option as `pixel_density` in request body', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt: TEST_PROMPT,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {
          pixelart: { pixelDensity: 16 },
        },
        files: undefined,
        mask: undefined,
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        model: 'pixelart-standard',
        prompt: TEST_PROMPT,
        n: 1,
        pixel_density: 16,
      });
    });

    it('should send all provider options together', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt: TEST_PROMPT,
        n: 2,
        size: '256x256',
        aspectRatio: undefined,
        seed: 7,
        providerOptions: {
          pixelart: { style: 'retro', pixelDensity: 8 },
        },
        files: undefined,
        mask: undefined,
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        model: 'pixelart-standard',
        prompt: TEST_PROMPT,
        n: 2,
        size: '256x256',
        seed: 7,
        style: 'retro',
        pixel_density: 8,
      });
    });

    it('should pass custom headers', async () => {
      const modelWithHeaders = createBasicModel({
        headers: {
