    });

    it('should return empty warnings array', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt: TEST_PROMPT,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(result.warnings).toStrictEqual([]);
    });

    it('should handle API errors', async () => {
      server.urls['https://api.example.com/v1/images/generate'].response = {
        type: 'error',
        status: 400,
        body: JSON.stringify({
          error: {
            message: 'Invalid size parameter',
            type: 'invalid_request_error',
            code: 'invalid_size',
          },
        }),
      };

      const model = createBasicModel();

      await expect(
        model.doGenerate({
          prompt: TEST_PROMPT,
          n: 1,
          size: '99x99',
          aspectRatio: undefined,
          seed: undefined,
          providerOptions: {},
          files: undefined,
          mask: undefined,
        }),
      ).rejects.toMatchObject({
        message: 'Invalid size parameter',
        statusCode: 400,
      });
    });

    it('should use model ID from API response when available', async () => {
      server.urls['https://api.example.com/v1/images/generate'].response = {
        type: 'json-value',
        body: {
          images: [{ b64_json: TEST_B64_IMAGE }],
          model: 'pixelart-standard-v2',
          created: 1700000000,
        },
      };

      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt: TEST_PROMPT,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(result.response.modelId).toBe('pixelart-standard-v2');
    });

    it('should fall back to constructor modelId when API response omits model', async () => {
      server.urls['https://api.example.com/v1/images/generate'].response = {
        type: 'json-value',
        body: {
          images: [{ b64_json: TEST_B64_IMAGE }],
          created: 1700000000,
        },
      };

      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt: TEST_PROMPT,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(result.response.modelId).toBe('pixelart-standard');
    });
  });
});

